import React, { useEffect, useState } from 'react';
import { Apple, BatteryFull, Search, Wifi } from 'lucide-react';

const MENU_ITEMS = ['Finder', 'File', 'Edit', 'View', 'Go', 'Window', 'Help'];

const formatClock = (date: Date) =>
  date.toLocaleString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });

const MenuBar: React.FC = () => {
  const [now, setNow] = useState(() => new Date());

  useEffect(() => {
    const timer = window.setInterval(() => setNow(new Date()), 15_000);
    return () => window.clearInterval(timer);
  }, []);

  return (
    <div className="absolute inset-x-0 top-0 z-[60] flex h-7 items-center justify-between bg-black/25 px-3 text-[13px] text-white/90 backdrop-blur-2xl">
      <div className="flex items-center gap-4">
        <Apple size={15} className="fill-white text-white" />
        {MENU_ITEMS.map((item, i) => (
          <button
            key={item}
            className={`hidden rounded px-1 transition-colors hover:bg-white/15 sm:block ${
              i === 0 ? 'font-semibold' : 'font-normal text-white/85'
            }`}
          >
            {item}
          </button>
        ))}
      </div>

      <div className="flex items-center gap-3.5">
        <BatteryFull size={18} className="text-white/90" />
        <Wifi size={15} className="text-white/90" />
        <Search size={14} className="text-white/90" />
        <span className="tabular-nums text-white/95">{formatClock(now)}</span>
      </div>
    </div>
  );
};

export default MenuBar;
